module RefModule(
    input clk,
    input load,
    input [3:0] data_in,
    input shift_in,
    output [3:0] data_out,
    output shift_out
);reg [3:0] unused_register;

always @(posedge clk) begin
    if (load) begin
        unused_register <= data_in;
    end else begin
        unused_register <= {shift_in, unused_register[3:1]};
    end
end

assign data_out = unused_register;
assign shift_out = unused_register[3];

endmodule
